using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ── AddItem Tests ──────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_IncludedInTotal()
    {
        _cart.AddItem("SKU1", 2, 10.00m);

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDifferentItems_AllIncludedInTotal()
    {
        _cart.AddItem("SKU1", 1, 5.00m);
        _cart.AddItem("SKU2", 3, 10.00m);

        Assert.AreEqual(35.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_UpdatesQuantity()
    {
        _cart.AddItem("SKU1", 2, 10.00m);
        _cart.AddItem("SKU1", 3, 10.00m);

        // 5 × 10 = 50
        Assert.AreEqual(50.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void AddItem_NullOrEmptySku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.AddItem(sku!, 1, 10.00m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-100)]
    public void AddItem_ZeroOrNegativeQuantity_ThrowsArgumentException(int quantity)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.AddItem("SKU1", quantity, 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.AddItem("SKU1", 1, -5.00m));
    }

    // ── RemoveItem Tests ───────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovedFromCart()
    {
        _cart.AddItem("SKU1", 1, 10.00m);
        _cart.AddItem("SKU2", 1, 20.00m);

        _cart.RemoveItem("SKU1");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFoundException()
    {
        Assert.ThrowsException<KeyNotFoundException>(() => _cart.RemoveItem("NOPE"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void RemoveItem_NullOrEmptySku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.RemoveItem(sku!));
    }

    // ── CalculateTotal Tests ───────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsQuantityTimesPrice()
    {
        _cart.AddItem("SKU1", 3, 7.50m);

        Assert.AreEqual(22.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfAll()
    {
        _cart.AddItem("A", 2, 5.00m);
        _cart.AddItem("B", 1, 12.00m);
        _cart.AddItem("C", 4, 3.25m);

        // 10 + 12 + 13 = 35
        Assert.AreEqual(35.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemovingItem_ExcludesRemovedItem()
    {
        _cart.AddItem("SKU1", 1, 10.00m);
        _cart.AddItem("SKU2", 1, 20.00m);
        _cart.RemoveItem("SKU1");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon Tests ──────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_Save10_Applies10PercentDiscount()
    {
        _cart.AddItem("SKU1", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Flat5_Applies5DollarDiscount()
    {
        _cart.AddItem("SKU1", 1, 20.00m);
        _cart.ApplyCoupon("FLAT5");

        Assert.AreEqual(15.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void ApplyCoupon_NullOrEmptyCode_ThrowsArgumentException(string? code)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_Flat5OnSmallTotal_FloorsAtZero()
    {
        _cart.AddItem("SKU1", 1, 3.00m);
        _cart.ApplyCoupon("FLAT5");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_NewCouponReplacesOld()
    {
        _cart.AddItem("SKU1", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10"); // 90
        _cart.ApplyCoupon("FLAT5");  // 100 - 5 = 95

        Assert.AreEqual(95.00m, _cart.CalculateTotal());
    }
}

